import{_ as t,o as a,c as r,ag as o}from"./chunks/framework.BYehg5q7.js";const u=JSON.parse('{"title":"Getting Started","description":"","frontmatter":{},"headers":[],"relativePath":"guide/getting-started.md","filePath":"guide/getting-started.md","lastUpdated":1775031224000}'),s={name:"guide/getting-started.md"};function i(n,e,l,d,p,h){return a(),r("div",null,[...e[0]||(e[0]=[o('<h1 id="getting-started" tabindex="-1">Getting Started <a class="header-anchor" href="#getting-started" aria-label="Permalink to &quot;Getting Started&quot;">​</a></h1><p>getbased is a blood work dashboard that turns your lab reports into interactive charts, trend analysis, and AI-powered interpretation. The app starts empty — your data is loaded by you, stored locally in your browser, and never uploaded anywhere by default.</p><h2 id="open-the-app" tabindex="-1">Open the App <a class="header-anchor" href="#open-the-app" aria-label="Permalink to &quot;Open the App&quot;">​</a></h2><p>The easiest way to get started is the hosted version at <strong><a href="https://getbased.health" target="_blank" rel="noreferrer">getbased.health</a></strong>. No installation required.</p><h3 id="tor" tabindex="-1">Tor <a class="header-anchor" href="#tor" aria-label="Permalink to &quot;Tor&quot;">​</a></h3><p>getbased is available as a Tor hidden service. Open the app in <a href="https://www.torproject.org/download/" target="_blank" rel="noreferrer">Tor Browser</a> and click the &quot;.onion available&quot; badge in the address bar, or go directly to the <a href="./tor-access.html">.onion address</a>. Sync, AI chat, and all features work over Tor.</p><h3 id="self-host" tabindex="-1">Self-host <a class="header-anchor" href="#self-host" aria-label="Permalink to &quot;Self-host&quot;">​</a></h3><p>If you prefer to run it yourself, clone the repository and start a local server:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">python3</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -m</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> http.server</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> 8000</span></span></code></pre></div><p>Then open <code>http://localhost:8000</code> in your browser. A local server is required because the app loads ES module scripts — opening <code>index.html</code> directly as a file will not work.</p><h2 id="install-as-a-pwa" tabindex="-1">Install as a PWA <a class="header-anchor" href="#install-as-a-pwa" aria-label="Permalink to &quot;Install as a PWA&quot;">​</a></h2><p>getbased is installable as a Progressive Web App on desktop and mobile. Look for the install prompt in your browser&#39;s address bar, or use your browser menu:</p><ul><li><strong>Chrome / Edge</strong>: address bar → install icon, or menu → &quot;Install getbased&quot;</li><li><strong>Safari (iOS)</strong>: Share → Add to Home Screen</li><li><strong>Firefox</strong>: menu → Install</li></ul><p>Once installed, the full app shell works offline. AI features (PDF import, chat) still need a network connection to reach your AI provider.</p><h2 id="chat-onboarding" tabindex="-1">Chat Onboarding <a class="header-anchor" href="#chat-onboarding" aria-label="Permalink to &quot;Chat Onboarding&quot;">​</a></h2><p>When you open the app for the first time, the chat panel guides you through setup in a conversational flow:</p><ol><li><strong>Profile</strong> — name, sex, date of birth, height, weight, location</li><li><strong>AI provider</strong> — connect OpenRouter (one-click OAuth), Anthropic, Venice, or Local AI. You can skip this step and set it up later</li><li><strong>Extras</strong> — menstrual cycle setup (female profiles), supplements &amp; medications, lifestyle context cards</li></ol><p>Each step is optional and skippable. The onboarding adapts based on your profile — female users get cycle tracking options (regular periods, perimenopause, postmenopause, pregnant, breastfeeding).</p><h2 id="guided-tour" tabindex="-1">Guided Tour <a class="header-anchor" href="#guided-tour" aria-label="Permalink to &quot;Guided Tour&quot;">​</a></h2><p>After you import your first lab data, a 7-step spotlight tour walks you through the key areas of the interface — the import button, category navigation, lifestyle context cards, settings, and the AI chat panel. Use the <strong>Next</strong> button to advance, or press <strong>Escape</strong> to dismiss.</p><p>You can replay the tour at any time from <strong>Settings → Display → Take a Tour</strong>.</p><h2 id="first-steps" tabindex="-1">First Steps <a class="header-anchor" href="#first-steps" aria-label="Permalink to &quot;First Steps&quot;">​</a></h2><h3 id="_1-configure-an-ai-provider" tabindex="-1">1. Configure an AI Provider <a class="header-anchor" href="#_1-configure-an-ai-provider" aria-label="Permalink to &quot;1. Configure an AI Provider&quot;">​</a></h3><p>PDF import, the AI chat panel, and several dashboard features require an AI provider. You can set this up during chat onboarding, or open <strong>Settings</strong> (gear icon in the header) and go to the <strong>AI Provider</strong> tab.</p><p>See the <a href="./ai-providers.html">AI Providers</a> page for a full comparison and setup instructions for each option.</p><div class="tip custom-block"><p class="custom-block-title">No provider needed for most features</p><p>Charts, manual entry, JSON import/export, data tables, trend alerts, and correlations all work without any AI provider configured.</p></div><h3 id="_2-set-your-profile" tabindex="-1">2. Set Your Profile <a class="header-anchor" href="#_2-set-your-profile" aria-label="Permalink to &quot;2. Set Your Profile&quot;">​</a></h3><p>Set your profile during chat onboarding, or edit via the <strong>Client List</strong> (click your profile name in the header). Your biological sex and date of birth affect:</p><ul><li>Reference ranges for sex-specific markers (hormones, hematology)</li><li>PhenoAge (biological age) calculation, which requires your DOB</li><li>Menstrual cycle tracking (available for female profiles)</li></ul><p>You can also track <strong>biometrics</strong> — height, weight, blood pressure, and resting pulse. Open the <strong>Edit Client</strong> form and expand the <strong>Biometrics</strong> section. Height is stored on your profile; weight, BP, and pulse are time-series (add entries with dates). BMI is auto-calculated from height and latest weight. Click the unit label (cm/in, kg/lbs) to switch units.</p><h3 id="_3-import-your-first-lab-report" tabindex="-1">3. Import Your First Lab Report <a class="header-anchor" href="#_3-import-your-first-lab-report" aria-label="Permalink to &quot;3. Import Your First Lab Report&quot;">​</a></h3><p>Click the <strong>import button</strong> (document icon, bottom-right) or drag and drop any lab PDF onto the page. The AI reads the report, maps results to known biomarkers, and shows you a preview before saving anything.</p><p>If you don&#39;t have a PDF handy, try one of the <strong>demo profiles</strong> first. On the welcome screen, click <strong>Sarah</strong> (iron &amp; hormones story) or <strong>Alex</strong> (metabolic health journey) to load a fully populated profile with 4 blood draws, fatty acid panels, supplements, context cards, EMF assessments, and notes. You can also load demo profiles later from the <strong>Client List</strong> (click your profile in the header) using the <strong>+ Demo Sarah</strong> or <strong>+ Demo Alex</strong> buttons.</p><p>Alternatively, use <strong>Manual Entry</strong> to type in values directly.</p><div class="warning custom-block"><p class="custom-block-title">AI provider required for PDF import</p><p>You must have an AI provider configured before dropping a PDF. If the drop zone shows a prompt to set up a provider, visit Settings first.</p></div><p>Once data is imported, charts and analysis appear automatically across all 16 biomarker categories.</p>',36)])])}const g=t(s,[["render",i]]);export{u as __pageData,g as default};
